// Input 1 = WhatsApp webhook
// Input 2 = Excel data

// FIX 1: unwrap Excel rows from .all() → each item is { json: { ... } }
const excelData = $('Get Stock data').all().map(item => item.json);

// Extract all product_items from WhatsApp order
const productItems = $('Whatsapp Bot Webhook').first().json.body.entry[0].changes[0].value.messages[0].order.product_items

// Collect errors
let errors = [];

for (const item of productItems) {
  const selectedId = String(item.product_retailer_id).trim();
  const selectedQty = Number(item.quantity);

  // FIX 2: normalize Excel IDs to string
  const match = excelData.find(p => String(p.id).trim() === selectedId);

  if (!match) {
    errors.push(`Product with ID ${selectedId} not found.`);
    continue;
  }

  const available = Number(match.item_available);

  if (available < selectedQty) {
    errors.push(
      `Only ${available} item(s) of "${match.title}" are available, but you selected ${selectedQty}.`
    );
  }
}

// FINAL DECISION
if (errors.length === 0) {
  return [
    {
      json: {
        success: true,
        message: "Stock available for all selected items."
      }
    }
  ];
} else {
  return [
    {
      json: {
        success: false,
        message: errors.join(" | ")
      }
    }
  ];
}

