// Load data from nodes
const product_data = $("Get Stock data").all().map(item => item.json);
const user_selected_data = $("Split Out").all().map(item => item.json);

// Final output list
let matched = [];

// Loop through user-selected items
for (const userItem of user_selected_data) {

  const selectedId = String(userItem.product_retailer_id).trim();

  // Find matching product from stock data
  const stockItem = product_data.find(
    p => String(p.id).trim() === selectedId
  );

  // If matched → append combined data
  if (stockItem) {
    matched.push({
      product_retailer_id: selectedId,
      title: stockItem.title,
      quantity: userItem.quantity
    });
  }
}

// Return result
return matched.map(m => ({ json: m }));

