// Load orders from sheet4
const order_list = $("Get row(s) in sheet4").all().map(item => item.json);

// If empty
if (!order_list.length) {
  return [{ json: { message: "You have no orders at the moment." } }];
}

// Group by Order ID
const grouped = {};

for (const row of order_list) {
  const orderId = row["Order ID"];

  if (!grouped[orderId]) {
    grouped[orderId] = {
      items: [],
      status: row.Status,
    };
  }

  grouped[orderId].items.push({
    item: row.Item,
    quantity: row.Quantity,
  });
}

// Build the message
let msg = "📦 *Your Order Summary*\n\nHere’s a quick overview of all your recent orders:\n\n";

for (const [orderId, data] of Object.entries(grouped)) {
  const totalQty = data.items.reduce((sum, i) => sum + Number(i.quantity), 0);

  msg += `🧾 *Order ID:* ${orderId}\n`;
  msg += `📦 *Total Items:* ${totalQty}\n`;
  msg += `📌 *Status:* ${data.status}\n`;
  msg += `🛍️ *Items:*\n`;

  for (const item of data.items) {
    msg += `   • ${item.item} ×${item.quantity}\n`;
  }

  msg += `\n`;
}

// msg += "💬 If you'd like to *track*, *change*, or *cancel* any order, just reply with the Order ID (e.g., *ORD-1764326177122-8178*).";

// Return final message
return [{ json: { message: msg } }];
